+fn ready_hybrid_high_bucket_priorities(priorities: Option<&[Priority]>) -> Vec<Priority> {
+    priorities.map_or_else(
+        || vec![Priority::CRITICAL, Priority::HIGH],
+        |values| {
+            values
+                .iter()
+                .copied()
+                .filter(|priority| ready_hybrid_bucket(*priority) == 0)
+                .collect()
+        },
+    )
+}
